449	    fn lower_call(&mut self, op: &str, args: &[Expr]) -> (Option<String>, String, bool) {
450	        if let Some(r) = self.lower_builtin(op, args) {
451	            return r;
452	        }
453	        if let Some(sig) = self.fns.get(op).cloned() {
454	            let mut argvals: Vec<(String, String)> = Vec::new(); // (type, value)
455	            for a in args {
456	                let (av, aty, div) = self.lower_expr(a);
457	                if div {
458	                    return (None, String::new(), true);
459	                }
460	                argvals.push((aty, av.unwrap()));
461	            }
462	            if sig.params.len() != argvals.len() {
463	                self.err(&format!("arity mismatch calling `{}`", op));
464	            }
465	            let rty = llvm_type(&sig.ret);
466	            let r = self.fresh();
467	            let typed: Vec<String> = argvals.iter().map(|(ty, v)| format!("{} {}", ty, v)).collect();
468	            self.out_str(&format!("  {} = call {} @aury__{}({})\n", r, rty, op, typed.join(", ")));
469	            (Some(r), rty, false)
470	        } else {
490	            Some((a.unwrap(), b.unwrap()))
491	        };
492	        match op {
493	            "i64.add" | "i64.sub" | "i64.mul" => {
494	                let (a, b) = two(self)?;
495	                let r = self.fresh();
496	                let k = if op == "i64.add" { "add" } else if op == "i64.sub" { "sub" } else { "mul" };
497	                self.out_str(&format!("  {} = {} i64 {}, {}\n", r, k, a, b));
498	                Some((Some(r), "i64".into(), false))
499	            }
500	            "i64.div" | "i64.mod" => {
501	                let (a, b) = two(self)?;
502	                let cz = self.fresh();
503	                self.out_str(&format!("  {} = icmp eq i64 {}, 0\n", cz, b));
504	                let trap = self.fresh_lbl("trap");
505	                let ok = self.fresh_lbl("ok");
506	                self.out_str(&format!("  br i1 {}, label %{}, label %{}\n", cz, trap, ok));
507	                self.out_str(&format!("{}:\n  call void @llvm.trap()\n  unreachable\n", trap));
508	                self.out_str(&format!("{}:\n", ok));
509	                let r = self.fresh();
510	                let k = if op == "i64.div" { "sdiv" } else { "srem" };
511	                self.out_str(&format!("  {} = {} i64 {}, {}\n", r, k, a, b));
512	                Some((Some(r), "i64".into(), false))
513	            }
514	            "i64.gt" | "i64.lt" | "i64.ge" | "i64.le" | "i64.eq" | "i64.neq" => {
515	                let (a, b) = two(self)?;
516	                let pred = match op {
517	                    "i64.gt" => "sgt", "i64.lt" => "slt", "i64.ge" => "sge",
518	                    "i64.le" => "sle", "i64.eq" => "eq", _ => "ne",
519	                };
520	                let c = self.fresh();
521	                self.out_str(&format!("  {} = icmp {} i64 {}, {}\n", c, pred, a, b));
522	                let r = self.fresh();
523	                self.out_str(&format!("  {} = zext i1 {} to i64\n", r, c));
524	                Some((Some(r), "i64".into(), false))
525	            }
526	            "i64.neg" => {
527	                if args.len() != 1 { return None; }
528	                let (a, aty, d) = self.lower_expr(&args[0]);
529	                if d { return Some((None, String::new(), true)); }
530	                if aty != "i64" { self.err("i64.neg needs i64"); }
531	                let r = self.fresh();
532	                self.out_str(&format!("  {} = sub i64 0, {}\n", r, a.unwrap()));
533	                Some((Some(r), "i64".into(), false))
534	            }
535	            "i64.abs" => {
536	                if args.len() != 1 { return None; }
537	                let (a, aty, d) = self.lower_expr(&args[0]);
538	                if d { return Some((None, String::new(), true)); }
539	                if aty != "i64" { self.err("i64.abs needs i64"); }
540	                let r = self.fresh();
541	                self.out_str(&format!("  {} = call i64 @llvm.abs.i64(i64 {}, i1 1)\n", r, a.unwrap()));
542	                Some((Some(r), "i64".into(), false))
543	            }
544	            "bool.and" | "bool.or" => {
545	                let (a, b) = two(self)?;
546	                let r = self.fresh();
547	                let k = if op == "bool.and" { "and" } else { "or" };
548	                self.out_str(&format!("  {} = {} i64 {}, {}\n", r, k, a, b));
549	                Some((Some(r), "i64".into(), false))
550	            }
551	            "bool.not" => {
552	                if args.len() != 1 { return None; }
553	                let (a, aty, d) = self.lower_expr(&args[0]);
554	                if d { return Some((None, String::new(), true)); }
555	                if aty != "i64" { self.err("bool.not needs bool"); }
556	                let r = self.fresh();
557	                self.out_str(&format!("  {} = xor i64 {}, 1\n", r, a.unwrap()));
558	                Some((Some(r), "i64".into(), false))
559	            }
560	            "bool.eq" => {
561	                let (a, b) = two(self)?;
562	                let c = self.fresh();
563	                self.out_str(&format!("  {} = icmp eq i64 {}, {}\n", c, a, b));
564	                let r = self.fresh();
565	                self.out_str(&format!("  {} = zext i1 {} to i64\n", r, c));
566	                Some((Some(r), "i64".into(), false))
567	            }
568	            // ---- str builtins ----
569	            "str.concat" => {
570	                if args.len() != 2 { return None; }
571	                let (a, aty, da) = self.lower_expr(&args[0]);
572	                if da { return Some((None, String::new(), true)); }
573	                let (b, bty, db) = self.lower_expr(&args[1]);
574	                if db { return Some((None, String::new(), true)); }
575	                if aty != "ptr" || bty != "ptr" { self.err("str.concat needs str"); }
576	                let r = self.fresh();
577	                self.out_str(&format!("  {} = call ptr @aury_str_concat(ptr {}, ptr {})\n", r, a.unwrap(), b.unwrap()));
578	                Some((Some(r), "ptr".into(), false))
579	            }
580	            "str.eq" => {
581	                if args.len() != 2 { return None; }
582	                let (a, _, da) = self.lower_expr(&args[0]);
583	                if da { return Some((None, String::new(), true)); }
584	                let (b, _, db) = self.lower_expr(&args[1]);
585	                if db { return Some((None, String::new(), true)); }
586	                let r = self.fresh();
587	                self.out_str(&format!("  {} = call i64 @aury_str_eq(ptr {}, ptr {})\n", r, a.unwrap(), b.unwrap()));
588	                Some((Some(r), "i64".into(), false))
589	            }
590	            "str.neq" => {
591	                if args.len() != 2 { return None; }
592	                let (a, _, da) = self.lower_expr(&args[0]);
593	                if da { return Some((None, String::new(), true)); }
594	                let (b, _, db) = self.lower_expr(&args[1]);
595	                if db { return Some((None, String::new(), true)); }
596	                let e = self.fresh();
597	                self.out_str(&format!("  {} = call i64 @aury_str_eq(ptr {}, ptr {})\n", e, a.unwrap(), b.unwrap()));
598	                let r = self.fresh();
599	                self.out_str(&format!("  {} = xor i64 {}, 1\n", r, e));
600	                Some((Some(r), "i64".into(), false))
601	            }
602	            "str.len" => {
603	                if args.len() != 1 { return None; }
604	                let (a, aty, d) = self.lower_expr(&args[0]);
605	                if d { return Some((None, String::new(), true)); }
606	                if aty != "ptr" { self.err("str.len needs str"); }
607	                let r = self.fresh();
608	                // str layout: { i64 len, ptr data } — load field 0.
609	                self.out_str(&format!("  {} = load i64, ptr {}\n", r, a.unwrap()));
610	                Some((Some(r), "i64".into(), false))
611	            }
612	            "i64.to_str" => {
613	                if args.len() != 1 { return None; }
614	                let (a, aty, d) = self.lower_expr(&args[0]);
615	                if d { return Some((None, String::new(), true)); }
616	                if aty != "i64" { self.err("i64.to_str needs i64"); }
617	                let r = self.fresh();
618	                self.out_str(&format!("  {} = call ptr @aury_i64_to_str(i64 {})\n", r, a.unwrap()));
619	                Some((Some(r), "ptr".into(), false))
620	            }
621	            "i64.parse" | "i64.from_str" => {
622	                if args.len() != 1 { return None; }
623	                let (a, aty, d) = self.lower_expr(&args[0]);
624	                if d { return Some((None, String::new(), true)); }
625	                if aty != "ptr" { self.err("i64.parse needs str"); }
626	                let r = self.fresh();
627	                self.out_str(&format!("  {} = call ptr @aury_i64_parse(ptr {})\n", r, a.unwrap()));
628	                Some((Some(r), "ptr".into(), false))
629	            }
630	            "result.is_ok" => {
631	                if args.len() != 1 { return None; }
632	                let (a, aty, d) = self.lower_expr(&args[0]);
633	                if d { return Some((None, String::new(), true)); }
634	                if aty != "ptr" { self.err("result.is_ok needs a result"); }
635	                // {i1 ok, ...} — load field 0 (i1).
636	                let c = self.fresh();
637	                self.out_str(&format!("  {} = load i1, ptr {}\n", c, a.unwrap()));
638	                let r = self.fresh();
639	                self.out_str(&format!("  {} = zext i1 {} to i64\n", r, c));
640	                Some((Some(r), "i64".into(), false))
641	            }
642	            _ => None,
643	        }
644	    }
