646	    /// cast: i64<->i64 identity; i64->str; str->i64 (parse, trap on failure);
647	    /// str->str identity.
648	    fn lower_cast(&mut self, target: &Type, value: &Expr) -> (Option<String>, String, bool) {
649	        let (v, vty, div) = self.lower_expr(value);
650	        if div {
651	            return (None, String::new(), true);
652	        }
653	        let v = v.unwrap();
654	        let tty = llvm_type(target);
655	        match (vty.as_str(), tty.as_str()) {
656	            ("i64", "i64") => (Some(v), "i64".into(), false),
657	            ("ptr", "ptr") => (Some(v), "ptr".into(), false),
658	            ("i64", "ptr") => {
659	                // i64 -> str
660	                let r = self.fresh();
661	                self.out_str(&format!("  {} = call ptr @aury_i64_to_str(i64 {})\n", r, v));
662	                (Some(r), "ptr".into(), false)
663	            }
664	            ("ptr", "i64") => {
665	                // str -> i64: parse to result, trap if !ok, else load val field.
666	                let res = self.fresh();
667	                self.out_str(&format!("  {} = call ptr @aury_i64_parse(ptr {})\n", res, v));
668	                let ok = self.fresh();
669	                self.out_str(&format!("  {} = load i1, ptr {}\n", ok, res));
670	                let good = self.fresh_lbl("castok");
671	                let bad = self.fresh_lbl("castbad");
672	                self.out_str(&format!("  br i1 {}, label %{}, label %{}\n", ok, good, bad));
673	                self.out_str(&format!("{}:\n  call void @llvm.trap()\n  unreachable\n", bad));
674	                self.out_str(&format!("{}:\n", good));
675	                let vp = self.fresh();
676	                self.out_str(&format!(
677	                    "  {} = getelementptr inbounds %aury.result, ptr {}, i64 0, i32 1\n",
678	                    vp, res
679	                ));
680	                let r = self.fresh();
680	                let r = self.fresh();
681	                self.out_str(&format!("  {} = load i64, ptr {}\n", r, vp));
682	                (Some(r), "i64".into(), false)
683	            }
684	            _ => {
685	                self.err(&format!("cast {}->{} not supported natively", vty, tty));
686	                (Some("0".into()), "i64".into(), false)
687	            }
688	        }
689	    }
