737	    fn lower_match(&mut self, scrut: &Expr, arms: &[MatchArm]) -> (Option<String>, String, bool) {
738	        let (sv, _, sdiv) = self.lower_expr(scrut);
739	        if sdiv {
740	            return (None, String::new(), true);
741	        }
742	        let sv = sv.unwrap();
743	        let rty = llvm_type(&self.infer_type(&arms[0].body));
744	        let res = format!("%.match.{}", self.reg);
745	        self.reg += 1;
746	        self.out_str(&format!("  {} = alloca {}\n", res, rty));
747	        let cont_lbl = self.fresh_lbl("cont");
748	        let mut any_nondiv = false;
749	        let mut next_lbl = self.fresh_lbl("arm");
750	        self.out_str(&format!("  br label %{}\n", next_lbl));
751	        for arm in arms.iter() {
752	            match &arm.pattern {
753	                Pattern::Wild | Pattern::Bind(_) => {
754	                    self.out_str(&format!("{}:\n", next_lbl));
755	                    let bind = if let Pattern::Bind(n) = &arm.pattern {
756	                        let s = self.slot(n, "i64");
757	                        self.out_str(&format!("  store i64 {}, ptr {}\n", sv, s));
758	                        self.scope.push((n.clone(), s, Type::I64));
759	                        Some(())
760	                    } else {
761	                        None
762	                    };
763	                    let (v, vty, div) = self.lower_expr(&arm.body);
764	                    if bind.is_some() {
765	                        self.scope.pop();
766	                    }
767	                    if !div {
768	                        self.out_str(&format!("  store {} {}, ptr {}\n", vty, v.unwrap(), res));
769	                        self.out_str(&format!("  br label %{}\n", cont_lbl));
770	                        any_nondiv = true;
771	                    }
772	                }
773	                Pattern::Lit(l) => {
774	                    let litval = match l {
775	                        Lit::I64(n) => n.to_string(),
776	                        Lit::Bool(b) => (if *b { 1 } else { 0 }).to_string(),
777	                        _ => {
778	                            self.err("non-i64/bool match literal");
779	                            "0".into()
780	                        }
781	                    };
782	                    self.out_str(&format!("{}:\n", next_lbl));
783	                    let c = self.fresh();
784	                    self.out_str(&format!("  {} = icmp eq i64 {}, {}\n", c, sv, litval));
785	                    let this_arm = self.fresh_lbl("arm");
786	                    let nxt = self.fresh_lbl("arm");
787	                    self.out_str(&format!("  br i1 {}, label %{}, label %{}\n", c, this_arm, nxt));
788	                    self.out_str(&format!("{}:\n", this_arm));
789	                    let (v, vty, div) = self.lower_expr(&arm.body);
790	                    if !div {
791	                        self.out_str(&format!("  store {} {}, ptr {}\n", vty, v.unwrap(), res));
792	                        self.out_str(&format!("  br label %{}\n", cont_lbl));
793	                        any_nondiv = true;
794	                    }
795	                    next_lbl = nxt;
796	                }
797	            }
798	        }
799	        if !any_nondiv {
800	            self.out_str(&format!("{}:\n  call void @llvm.trap()\n  unreachable\n", next_lbl));
801	            return (None, String::new(), true);
802	        }
803	        self.out_str(&format!("{}:\n", cont_lbl));
804	        let r = self.fresh();
805	        self.out_str(&format!("  {} = load {}, ptr {}\n", r, rty, res));
806	        (Some(r), rty, false)
807	    }
