809	    fn lower_loop(&mut self, body: &Expr) -> (Option<String>, String, bool) {
810	        let loop_lbl = self.fresh_lbl("loop");
811	        self.out_str(&format!("  br label %{}\n", loop_lbl));
812	        self.out_str(&format!("{}:\n", loop_lbl));
813	        let (_, _, div) = self.lower_expr(body);
814	        if div {
815	            return (None, String::new(), true);
816	        }
817	        self.out_str(&format!("  br label %{}\n", loop_lbl));
818	        (None, String::new(), true)
819	    }
