821	    fn lookup(&mut self, name: &str) -> (String, Type) {
822	        for (n, s, ty) in self.scope.iter().rev() {
823	            if n == name {
824	                return (s.clone(), ty.clone());
825	            }
826	        }
827	        self.err(&format!("unbound ref `{}` in native lowering", name));
828	        ("%.bad".to_string(), Type::I64)
829	    }
830	}
