832	impl Lowerer {
833	    /// Infer the Aury type of an expression (mirrors the validator's rules for
834	    /// the supported subset) so if/match result slots get the right LLVM type.
835	    /// Uses a local env threaded through `let` bindings.
836	    fn infer_type(&self, e: &Expr) -> Type {
837	        let env: Vec<(String, Type)> = self.scope.iter().map(|(n, _, t)| (n.clone(), t.clone())).collect();
838	        self.infer_env(e, &env)
839	    }
840	    fn infer_env(&self, e: &Expr, env: &[(String, Type)]) -> Type {
841	        match e {
842	            Expr::Lit { value, .. } => match value {
843	                Lit::I64(_) => Type::I64,
844	                Lit::Bool(_) => Type::Bool,
845	                Lit::Str(_) => Type::Str,
846	                Lit::Unit => Type::Unit,
847	            },
848	            Expr::Ref { name, .. } => env
849	                .iter().rev()
850	                .find(|(n, _)| n == name)
851	                .map(|(_, t)| t.clone())
852	                .unwrap_or(Type::I64),
853	            Expr::Let { name, ty, body, .. } => {
854	                let mut e2: Vec<(String, Type)> = env.to_vec();
855	                e2.push((name.clone(), ty.clone()));
856	                self.infer_env(body, &e2)
857	            }
858	            Expr::Call { op, .. } => self.builtin_ret(op),
859	            Expr::If { then, .. } => self.infer_env(then, env),
860	            Expr::Match { arms, .. } => arms
245	        .unwrap_or_default();
246	    let positional: Vec<&String> = args
247	        .iter()
248	        .enumerate()
249	        .filter(|(i, a)| {
250	            !excluded.contains(i) && !a.starts_with("--") && !(a.as_str() == "-o")
251	        })
252	        .map(|(_, a)| a)
253	        .collect();
254	    let out = o_idx.and_then(|i| args.get(i + 1)).cloned();
255	    let path = positional.first().ok_or("compile <file> <fn> [args...] [-o out]")?;
256	    let entry = positional.get(1).ok_or("compile <file> <fn> [args...]")?;
257	    let arg_strs = if positional.len() >= 3 {
258	        &positional[2..]
259	    } else {
260	        &[]
261	    };
262	    let m = build(path)?;
263	    if let ValidationOutcome::Rejected(rejs) = check_module(&m) {
264	        eprintln!("rejected before compile: {} rejection(s)", rejs.len());
265	        for r in &rejs {
266	            eprintln!("{}", r.to_json());
267	        }
268	        return Ok(ExitCode::from(1));
269	    }
270	    let mut iargs: Vec<i64> = Vec::new();
271	    for a in arg_strs {
272	        iargs.push(
273	            a.parse::<i64>()
274	                .map_err(|_| format!("compile: arg `{}` is not an i64", a))?,
275	        );
276	    }
277	    let ir = aury::lower::lower_program_with_main(&m, entry, &iargs)?;
278	    let ll = std::env::temp_dir().join(format!("aury_{}.ll", entry));
279	    std::fs::write(&ll, &ir).map_err(|e| format!("write ll: {}", e))?;
280	    let exe = out.unwrap_or_else(|| {
281	        let p = path.trim_end_matches(".aury");
282	        format!("{}.{}.exe", p, entry)
283	    });
284	    // Assemble + link with clang (also runs mem2reg + optimization). Link the
285	    // Aury runtime (str/result ops) alongside the generated IR.
286	    let rt = format!("{}/runtime/aury_rt.c", env!("CARGO_MANIFEST_DIR"));
287	    let status = std::process::Command::new("clang")
288	        .arg("-O2")
289	        .arg(&ll)
290	        .arg(&rt)
291	        .arg("-o")
292	        .arg(&exe)
