208	/// Build a runnable native program: lower the reachable set from `entry_fn`,
209	/// add a C `main` that calls it with `args` and prints the result.
210	pub fn lower_program_with_main(module: &Module, entry_fn: &str, args: &[String]) -> Result<String, String> {
211	    let mut ir = lower_set(module, &reachable(module, entry_fn), false)?;
212	    let sig = module
213	        .items
214	        .iter()
215	        .find_map(|it| match it {
216	            ModuleItem::Fn(f) if f.name == entry_fn => Some(f.clone()),
217	            _ => None,
218	        })
219	        .ok_or_else(|| format!("entry fn `{}` not found", entry_fn))?;
220	    let supported_ret = matches!(sig.ret, Type::I64 | Type::Bool | Type::Str);
221	    if !supported_ret {
222	        return Err(format!(
223	            "compile: entry fn `{}` returns {:?}, only i64/bool/str printable natively",
224	            entry_fn, sig.ret
225	        ));
226	    }
227	    if sig.params.len() != args.len() {
228	        return Err(format!(
229	            "compile: entry fn `{}` takes {} args, got {}",
230	            entry_fn,
231	            sig.params.len(),
232	            args.len()
233	        ));
234	    }
235	    for p in &sig.params {
236	        if !matches!(p.ty, Type::I64 | Type::Bool | Type::Str) {
237	            return Err(format!("compile: entry fn `{}` has unsupported param type {:?}", entry_fn, p.ty));
238	        }
239	    }
240	    // Build arg list: i64/bool args become i64 constants; str args become
241	    // string-literal globals (ptr).
242	    let mut arglist: Vec<String> = Vec::new();
243	    let mut str_globals: Vec<(String, String, String, usize)> = Vec::new();
244	    for (i, p) in sig.params.iter().enumerate() {
245	        match p.ty {
246	            Type::Str => {
247	                let data_name = format!("@.argd{}", i);
248	                let struct_name = format!("@.arg{}", i);
249	                let bytes = args[i].as_bytes();
250	                let len = bytes.len();
251	                let mut esc = String::new();
252	                for b in bytes {
253	                    match *b {
254	                        b'\\' => esc.push_str("\\\\"),
255	                        b'"' => esc.push_str("\\22"),
256	                        c if c.is_ascii_graphic() || c == b' ' => esc.push(c as char),
257	                        c => esc.push_str(&format!("\\{:02X}", c)),
258	                    }
259	                }
260	                esc.push_str("\\00");
261	                str_globals.push((data_name, struct_name, esc, len));
262	                arglist.push(format!("ptr {}", struct_name));
263	            }
264	            _ => {
265	                let n: i64 = args[i].parse().map_err(|_| format!("compile: arg `{}` is not an i64", args[i]))?;
266	                arglist.push(format!("i64 {}", n));
267	            }
268	        }
269	    }
270	    for (data_name, struct_name, esc, len) in &str_globals {
271	        ir.push_str(&format!("{} = private constant [{} x i8] c\"{}\"\n", data_name, len + 1, esc));
272	        ir.push_str(&format!("{} = private constant {{ i64, ptr }} {{ i64 {}, ptr {} }}\n", struct_name, len, data_name));
273	    }
274	    ir.push_str("define i32 @main() {\nentry:\n");
275	    ir.push_str(&format!("  %r = call {} @aury__{}({})\n", llvm_type(&sig.ret), entry_fn, arglist.join(", ")));
276	    match sig.ret {
277	        Type::Bool => {
278	            ir.push_str("  %c = icmp ne i64 %r, 0\n");
279	            ir.push_str("  br i1 %c, label %t, label %f\n");
280	            ir.push_str("t:\n  call i32 @printf(ptr @.t)\n  ret i32 0\n");
281	            ir.push_str("f:\n  call i32 @printf(ptr @.f)\n  ret i32 0\n}\n");
282	        }
283	        Type::Str => {
284	            ir.push_str("  call i32 @printf(ptr @.s, ptr %r)\n  ret i32 0\n}\n");
285	        }
420	                (Some("0".into()), "i64".into(), false)
421	            }
422	        }
423	    }
