425	    /// Emit a string literal as two globals ({i64,len; ptr data} + the bytes)
426	    /// and return the address (a `ptr`).
427	    fn str_literal(&mut self, s: &str) -> String {
428	        let n = self.str_n;
429	        self.str_n += 1;
430	        let bytes = s.as_bytes();
431	        let len = bytes.len();
432	        let data_name = format!("@.sd{}", n);
433	        let struct_name = format!("@.s{}", n);
434	        let mut esc = String::new();
435	        for b in bytes {
436	            match *b {
437	                b'\\' => esc.push_str("\\\\"),
438	                b'"' => esc.push_str("\\22"),
439	                c if c.is_ascii_graphic() || c == b' ' => esc.push(c as char),
440	                c => esc.push_str(&format!("\\{:02X}", c)),
441	            }
442	        }
443	        esc.push_str("\\00");
444	        // buffer; globals may not appear inside function bodies
445	        self.str_literals.push((data_name, struct_name, esc, len));
446	        struct_name
447	    }
