691	    fn lower_if(&mut self, cond: &Expr, then: &Expr, els: &Expr) -> (Option<String>, String, bool) {
692	        let (cv, cty, cdiv) = self.lower_expr(cond);
693	        if cdiv {
694	            return (None, String::new(), true);
695	        }
696	        if cty != "i64" {
697	            self.err("if condition must be bool");
698	        }
699	        let cz = self.fresh();
700	        self.out_str(&format!("  {} = icmp ne i64 {}, 0\n", cz, cv.unwrap()));
701	        let res = format!("%.if.{}", self.reg);
702	        self.reg += 1;
703	        // need the result type — lower then first to learn it (validator guarantees branches agree)
704	        // but we must allocate the slot BEFORE the br, and we don't know the type yet.
705	        // Trick: lower then in a tentative way? Simpler: the validator guarantees then/else share
706	        // a type; compute it from the AST type info we don't have. Instead, lower then, capture
707	        // its type, then allocate the slot with that type. The slot alloca must precede the br, but
708	        // we can lower cond, emit icmp, then lower then to LEARN the type, then alloca, then br,
709	        // then re-emit then? That double-lowers then. Instead: peek the type via a small helper.
710	        let rty = llvm_type(&self.infer_type(then));
711	        self.out_str(&format!("  {} = alloca {}\n", res, rty));
712	        let then_lbl = self.fresh_lbl("then");
713	        let else_lbl = self.fresh_lbl("else");
714	        let cont_lbl = self.fresh_lbl("cont");
715	        self.out_str(&format!("  br i1 {}, label %{}, label %{}\n", cz, then_lbl, else_lbl));
716	        self.out_str(&format!("{}:\n", then_lbl));
717	        let (tv, tty, tdiv) = self.lower_expr(then);
718	        if !tdiv {
719	            self.out_str(&format!("  store {} {}, ptr {}\n", tty, tv.unwrap(), res));
720	            self.out_str(&format!("  br label %{}\n", cont_lbl));
721	        }
722	        self.out_str(&format!("{}:\n", else_lbl));
723	        let (ev, ety, ediv) = self.lower_expr(els);
724	        if !ediv {
725	            self.out_str(&format!("  store {} {}, ptr {}\n", ety, ev.unwrap(), res));
726	            self.out_str(&format!("  br label %{}\n", cont_lbl));
727	        }
728	        if tdiv && ediv {
729	            return (None, String::new(), true);
730	        }
731	        self.out_str(&format!("{}:\n", cont_lbl));
732	        let r = self.fresh();
733	        self.out_str(&format!("  {} = load {}, ptr {}\n", r, rty, res));
734	        (Some(r), rty, false)
735	    }
