 56	    aury_result r = (aury_result)malloc(sizeof(aury_result_t));
 57	    const char* d = s->data;
 58	    int64_t n = 0; int i = 0; int neg = 0; int any = 0;
 59	    if (d[0] == '-') { neg = 1; i = 1; } else if (d[0] == '+') { i = 1; }
 60	    for (; i < s->len; i++) {
 61	        if (d[i] < '0' || d[i] > '9') break;
 62	        n = n * 10 + (d[i] - '0');
