273	fn native_lowering_matches_interpreter_for_numeric_core() {
274	    // The correctness contract for the lowering: a program compiled to native
275	    // code via clang must produce the SAME result as the interpreter. This is
276	    // the strong equivalence check — it catches any lowering bug (SSA, control
277	    // flow, divergence, builtin mapping) by running both and comparing.
278	    let src = std::fs::read_to_string("examples/math.aury").unwrap();
279	    let xs = parse(&src).unwrap();
280	    let m = build_module(&xs[0]).unwrap();
281	    // lower the reachable set from gcd (i64/bool core only)
282	    let ir = aury::lower::lower_program_with_main(&m, "gcd", &[1071, 462]).unwrap();
283	    assert!(ir.contains("define i64 @aury__gcd"));
284	    assert!(ir.contains("define i32 @main"));
285	    // vec/struct fns in math must NOT appear (they're outside the reachable set)
286	    assert!(!ir.contains("@aury__poly-eval"), "unreachable vec fn should not be lowered");
287	    // bring your own clang: this test verifies the IR is well-formed by the
288	    // equivalence it implies; if clang is absent we still assert the IR shape.
289	    if std::process::Command::new("clang").arg("--version").output().is_ok() {
290	        let ll = std::env::temp_dir().join("aury_test_gcd.ll");
291	        std::fs::write(&ll, &ir).unwrap();
292	        let exe = std::env::temp_dir().join("aury_test_gcd.exe");
293	        let st = std::process::Command::new("clang")
294	            .args(["-O2", ll.to_str().unwrap(), "-o", exe.to_str().unwrap()])
295	            .output()
296	            .unwrap();
297	        assert!(st.status.success(), "clang failed:\n{}", String::from_utf8_lossy(&st.stderr));
